pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_FILTER.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            float_parameter("level_in", "In Level", None, Some(1.0), 0.015625, 64.0, 0.1, ParameterUnit::None),
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("filters", "Filters Type", None, Some(0.0), 0.0, 2.0, 0.01, ParameterUnit::None),
            float_parameter("gainscale1", "Gain scale 1", None, Some(18.0), 6.0, 30.0, 0.1, ParameterUnit::Decibels),
            float_parameter("gainscale2", "Gain scale 2", None, Some(18.0), 6.0, 30.0, 0.1, ParameterUnit::Decibels),
            float_parameter("level_out", "Out Level", None, Some(1.0), 0.015625, 64.0, 0.1, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let level_in = required_f32(params, "level_in").map_err(anyhow::Error::msg)?;
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let filters = required_f32(params, "filters").map_err(anyhow::Error::msg)?;
    let gainscale1 = required_f32(params, "gainscale1").map_err(anyhow::Error::msg)?;
    let gainscale2 = required_f32(params, "gainscale2").map_err(anyhow::Error::msg)?;
    let level_out = required_f32(params, "level_out").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_LEVEL_IN, level_in),
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_FILTERS, filters),
        (PORT_CTRL_GAINSCALE1, gainscale1),
        (PORT_CTRL_GAINSCALE2, gainscale2),
        (PORT_CTRL_LEVEL_OUT, level_out),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: FilterModelDefinition = FilterModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: FilterBackendKind::Lv2, schema, build,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};
